() => {
  const canvas = document.querySelector('#game');
  const rect = canvas.getBoundingClientRect();
  const ctx = canvas.getContext('2d');
  const data = ctx.getImageData(0, 0, canvas.width, canvas.height).data;
  let colored = 0;
  for (let i = 0; i < data.length; i += 400) {
    if (data[i] || data[i + 1] || data[i + 2]) colored += 1;
  }
  return {
    title: document.title,
    canvasCssSize: [Math.round(rect.width), Math.round(rect.height)],
    canvasPixels: [canvas.width, canvas.height],
    sampledColoredPixels: colored,
    score: document.querySelector('#score').textContent,
    shots: document.querySelector('#shots').textContent,
    targets: document.querySelector('#targets').textContent,
    message: document.querySelector('#message').textContent
  };
}

