async () => {
  const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const send = (type, key) => window.dispatchEvent(new KeyboardEvent(type, { key, bubbles: true, cancelable: true }));
  send('keydown', 'ArrowRight');
  await wait(165);
  send('keyup', 'ArrowRight');
  send('keydown', ' ');
  await wait(850);
  send('keyup', ' ');
  await wait(2400);
  return {
    score: document.querySelector('#score').textContent,
    shots: document.querySelector('#shots').textContent,
    targets: document.querySelector('#targets').textContent,
    message: document.querySelector('#message').textContent
  };
}

